    {"name": "南瓜小米糊", "calories": 240, "protein": 4.6, "carbs": 40.8, "price": 5.7, "category": "粥羹", "intro": "南瓜小米糊是温和养胃的流质早餐，特别适合消化功能较弱或术后恢复期的人群。", "taste": "质地细腻如丝绒，南瓜的自然甜味柔和，小米的谷物香淡淡萦绕。", "steps": [{"step": 1, "detail": "南瓜去皮去瓤切小块，小米淘洗干净", "time": "5分钟", "temp": "-"}, {"step": 2, "detail": "南瓜和小米加500ml水入锅大火煮开", "time": "5分钟", "temp": "大火"}, {"step": 3, "detail": "转小火煮20分钟至南瓜和小米软烂", "time": "20分钟", "temp": "小火"}, {"step": 4, "detail": "加入冰糖，用料理棒打成细腻糊状即可", "time": "2分钟", "temp": "小火"}], "ingredients": [{"name": "南瓜", "price": 4.0, "quantity": "100g"}, {"name": "小米", "price": 1.5, "quantity": "40g"}, {"name": "冰糖", "price": 0.2, "quantity": "5g"}], "img": "breakfast.png"},
    {"name": "肉松饭团", "calories": 350, "protein": 6.6, "carbs": 36.5, "price": 3.4, "category": "米饭类", "intro": "肉松饭团是日式风格的便携早餐，可以用保鲜膜包裹带走，是学生和上班族的便捷之选。", "taste": "米饭软糯微黏，肉松咸香松软，海苔的鲜味和白芝麻的焦香层层递进。", "steps": [{"step": 1, "detail": "热米饭趁热加入白芝麻拌匀", "time": "1分钟", "temp": "-"}, {"step": 2, "detail": "手心沾少许水防粘，取适量米饭压扁", "time": "1分钟", "temp": "-"}, {"step": 3, "detail": "中间放入肉松，包成三角形或圆形饭团", "time": "2分钟", "temp": "-"}, {"step": 4, "detail": "底部包上海苔，撒海苔碎装饰即可", "time": "1分钟", "temp": "-"}], "ingredients": [{"name": "米饭", "price": 0.8, "quantity": "100g"}, {"name": "肉松", "price": 2.0, "quantity": "15g"}, {"name": "海苔碎", "price": 0.5, "quantity": "2g"}, {"name": "白芝麻", "price": 0.1, "quantity": "1g"}], "img": "breakfast.png"},
    {"name": "牛奶炖蛋", "calories": 220, "protein": 18.0, "carbs": 15.6, "price": 5.3, "category": "粥羹", "intro": "牛奶炖蛋是广东经典甜品改良的早餐版，蒸制而成无需用油，口感如布丁般嫩滑。", "taste": "质地似豆腐脑般细腻滑嫩，牛奶的醇香甜美，入口即化，老少皆宜。", "steps": [{"step": 1, "detail": "鸡蛋打散加白糖搅匀，倒入牛奶继续搅拌", "time": "3分钟", "temp": "-"}, {"step": 2, "detail": "用细筛过滤2遍去除泡沫和蛋筋", "time": "2分钟", "temp": "-"}, {"step": 3, "detail": "倒入碗中盖保鲜膜，用牙签扎几个小孔", "time": "1分钟", "temp": "-"}, {"step": 4, "detail": "水开后上锅中火蒸10分钟，关火焖3分钟", "time": "13分钟", "temp": "中火→余温"}], "ingredients": [{"name": "鸡蛋", "price": 2.4, "quantity": "2个"}, {"name": "纯牛奶", "price": 2.8, "quantity": "200ml"}, {"name": "白糖", "price": 0.1, "quantity": "5g"}], "img": "breakfast.png"},
    {"name": "土豆丝煎饼", "calories": 310, "protein": 12.0, "carbs": 47.9, "price": 3.6, "category": "面点", "intro": "土豆丝煎饼是中式街头早点家常版，外焦里嫩，一饼满足碳水和蛋白质需求。", "taste": "外皮煎至金黄酥脆，内里土豆丝软糯，葱香四溢，蘸醋更美味。", "steps": [{"step": 1, "detail": "土豆去皮擦细丝，加面粉、鸡蛋、葱花和少许盐拌匀", "time": "5分钟", "temp": "-"}, {"step": 2, "detail": "平底锅倒少许油中火预热", "time": "1分钟", "temp": "中火"}, {"step": 3, "detail": "取适量土豆丝面糊入锅，用铲子压平成圆形薄饼", "time": "30秒", "temp": "中火"}, {"step": 4, "detail": "煎3分钟至底面金黄翻面，再煎3分钟出锅", "time": "6分钟", "temp": "中火"}], "ingredients": [{"name": "土豆", "price": 1.8, "quantity": "150g"}, {"name": "面粉", "price": 0.4, "quantity": "30g"}, {"name": "鸡蛋", "price": 1.2, "quantity": "1个"}, {"name": "葱花", "price": 0.2, "quantity": "5g"}], "img": "breakfast.png"},
    {"name": "豆浆+油条（半根）", "calories": 250, "protein": 9.0, "carbs": 17.5, "price": 4.0, "category": "面点", "intro": "豆浆油条是中国最经典的早餐组合之一，无糖豆浆搭配半根油条，在满足感与健康间取得平衡。", "taste": "豆浆醇厚豆香浓郁，油条外酥内软，蘸入豆浆后吸满汁水口感独特。", "steps": [{"step": 1, "detail": "无糖豆浆倒入杯中微波炉高火加热2分钟或锅中加热至微沸", "time": "2分钟", "temp": "高火/中火"}, {"step": 2, "detail": "油条用烤箱180°C复烤3分钟恢复酥脆", "time": "3分钟", "temp": "180°C"}, {"step": 3, "detail": "豆浆倒入碗中，油条撕成小段", "time": "1分钟", "temp": "-"}, {"step": 4, "detail": "油条蘸豆浆食用，一次只吃半根控制热量", "time": "-", "temp": "-"}], "ingredients": [{"name": "无糖豆浆", "price": 2.5, "quantity": "250ml"}, {"name": "油条", "price": 1.5, "quantity": "半根"}], "img": "breakfast.png"},
    {"name": "西葫芦鸡蛋饼", "calories": 270, "protein": 11.0, "carbs": 32.2, "price": 2.7, "category": "面点", "intro": "西葫芦鸡蛋饼是韩式风味早餐饼，西葫芦含水量高使饼体格外嫩滑，成本低廉营养丰富。", "taste": "饼体柔软湿润，西葫芦清甜多汁，蛋香和面香交融，蘸酱油更提鲜。", "steps": [{"step": 1, "detail": "西葫芦擦细丝加少许盐腌5分钟，挤去多余水分", "time": "5分钟", "temp": "-"}, {"step": 2, "detail": "加入鸡蛋、面粉和盐搅拌成均匀面糊", "time": "2分钟", "temp": "-"}, {"step": 3, "detail": "平底锅中火倒油，舀面糊入锅摊成小圆饼", "time": "30秒", "temp": "中火"}, {"step": 4, "detail": "每面煎2-3分钟至金黄即可", "time": "5分钟", "temp": "中火"}], "ingredients": [{"name": "西葫芦", "price": 1.0, "quantity": "80g"}, {"name": "鸡蛋", "price": 1.2, "quantity": "1个"}, {"name": "面粉", "price": 0.5, "quantity": "40g"}, {"name": "盐", "price": 0.0, "quantity": "0.5g"}], "img": "breakfast.png"},
    {"name": "红枣银耳羹", "calories": 150, "protein": 2.2, "carbs": 30.4, "price": 4.7, "category": "粥羹", "intro": "红枣银耳羹是传统滋补甜羹，银耳富含胶质有助滋润肌肤，红枣补气血，是女性养颜早餐佳品。", "taste": "银耳滑糯胶质满满，红枣甘甜如蜜，汤羹浓稠挂勺，温润入心。", "steps": [{"step": 1, "detail": "干银耳提前用冷水泡发2小时，去蒂撕小朵", "time": "2小时", "temp": "冷水"}, {"step": 2, "detail": "银耳加800ml水入锅大火烧开", "time": "5分钟", "temp": "大火"}, {"step": 3, "detail": "转小火熬40分钟至银耳出胶汤变浓稠", "time": "40分钟", "temp": "小火"}, {"step": 4, "detail": "加红枣和冰糖再煮15分钟，最后加枸杞煮2分钟即可", "time": "17分钟", "temp": "小火"}], "ingredients": [{"name": "干银耳", "price": 2.5, "quantity": "10g"}, {"name": "红枣", "price": 1.5, "quantity": "5颗"}, {"name": "枸杞", "price": 0.5, "quantity": "3g"}, {"name": "冰糖", "price": 0.2, "quantity": "5g"}], "img": "breakfast.png"}
